function Karatsuba(x, y):
    // Input: Two non-negative integers x and y as strings or arrays of digits
    // Output: Product x * y

    n = max(length(x), length(y))
    if n == 1:
        return x * y  // Base case: single-digit multiplication

    // Make lengths equal by padding with leading zeros if necessary
    while length(x) < n:
        x = '0' + x
    while length(y) < n:
        y = '0' + y

    m = ceil(n / 2)
    high1, low1 = split(x, m)  // x = high1 * 10^m + low1
    high2, low2 = split(y, m)  // y = high2 * 10^m + low2

    z0 = Karatsuba(low1, low2)
    z1 = Karatsuba((high1 + low1), (high2 + low2))
    z2 = Karatsuba(high1, high2)

    // Combine results: x*y = z2 * 10^(2m) + (z1 - z2 - z0) * 10^m + z0
    return z2 * 10^(2m) + (z1 - z2 - z0) * 10^m + z0

