function Karatsuba(x, y):
    // Input: x and y as strings of digits in base B, length n
    // Output: product as integer or string

    n = max(length(x), length(y))
    // Pad x and y with leading zeros to length n
    x = pad(x, n)
    y = pad(y, n)

    // Base case: if n is small, use standard multiplication
    if n == 1:
        return x * y  // as integers

    m = ceil(n / 2)

    // Split x and y into high and low parts
    x_high = x[0 : n-m]  // most significant digits
    x_low = x[n-m : n]   // least significant digits
    y_high = y[0 : n-m]
    y_low = y[n-m : n]

    // Recursively compute the three products
    z0 = Karatsuba(x_low, y_low)
    z2 = Karatsuba(x_high, y_high)
    z1 = Karatsuba((x_high + x_low), (y_high + y_low)) - z2 - z0

    // Combine the results
    result = z2 * B^(2*m) + z1 * B^m + z0
    return result

