function find_first_occurrence(P, T):
    m = |P|, n = |T|
    S = P concatenated with T  // length m+n
    π = array of size m+n initialized to 0

    // Compute prefix function for S
    for i = 1 to m+n-1:
        j = π[i-1]
        while j > 0 and S[i] != S[j]:
            j = π[j-1]
        if S[i] == S[j]:
            j = j + 1
        π[i] = j

    // Search for occurrence
    for i = 2*m - 1 to m+n-1:
        if π[i] >= m:
            return i - 2*m + 1
    return -1

