function RabinKarp(T[0..n-1], P[0..m-1], d, q):
    // T: text of length n
    // P: pattern of length m
    // d: base for hash calculation (size of alphabet)
    // q: modulus for hash function (prime number)

    h = 1  // will store d^(m-1) mod q
    for i = 1 to m-1:
        h = (h * d) % q

    p = 0  // hash value for pattern
    t = 0  // hash value for current text window

    // Compute hash for pattern and first window
    for i = 0 to m-1:
        p = (d * p + P[i]) % q
        t = (d * t + T[i]) % q

    // Slide the pattern over text
    for s = 0 to n-m:
        if p == t:
            // Hash match - check character by character
            match = true
            for j = 0 to m-1:
                if T[s+j] != P[j]:
                    match = false
                    break
            if match:
                print "Pattern found at index", s

        // Compute hash for next window using rolling hash
        if s < n-m:
            t = (d * (t - T[s] * h) + T[s+m]) % q
            if t < 0:  // Ensure positive value
                t = t + q

