function jarvisMarch(points):
    n = length(points)
    if n < 3:
        return points  # Convex hull requires at least 3 points

    // Find the leftmost point (smallest x, and smallest y if tie)
    leftmost = 0
    for i from 1 to n-1:
        if points[i].x < points[leftmost].x:
            leftmost = i
        else if points[i].x == points[leftmost].x and points[i].y < points[leftmost].y:
            leftmost = i

    hull = []                 // List to store hull vertices
    current = leftmost

    repeat:
        hull.append(points[current])

        // Choose an initial candidate for the next point (different from current)
        if current == 0:
            next = 1
        else:
            next = 0

        for i from 0 to n-1:
            if i == current:
                continue

            // Compute cross product: (next - current) × (i - current)
            cross = (points[next].x - points[current].x) * (points[i].y - points[current].y) -
                    (points[next].y - points[current].y) * (points[i].x - points[current].x)

            if cross > 0:
                // points[i] is more counterclockwise than current next
                next = i
            else if cross == 0:
                // Collinear: choose the point farther from current
                dist_next = (points[next].x - points[current].x)^2 + (points[next].y - points[current].y)^2
                dist_i    = (points[i].x    - points[current].x)^2 + (points[i].y    - points[current].y)^2
                if dist_i > dist_next:
                    next = i

        current = next
    until current == leftmost

    return hull

